import express, { Request, Response } from 'express';
import { createConnection, getRepository } from 'typeorm';
import { Product } from './entity/Product'; // Adjust the import path as necessary

const app = express();
const PORT = process.env.PORT || 3000;

app.get('/products', async (req: Request, res: Response) => {
    try {
        const { name, category, minPrice, maxPrice, sortBy } = req.query;
        let query = `SELECT * FROM product WHERE 1=1`;

        if (name) {
            query += ` AND LOWER(name) LIKE LOWER('%${name}%')`;
        }

        if (category) {
            query += ` AND category = '${category}'`;
        }

        if (minPrice && !isNaN(Number(minPrice))) {
            query += ` AND price >= ${Number(minPrice)}`;
        }

        if (maxPrice && !isNaN(Number(maxPrice))) {
            query += ` AND price <= ${Number(maxPrice)}`;
        }

        if (sortBy) {
            query += ` ORDER BY ${sortBy}`;
        }

        const products = await getRepository(Product).query(query);
        res.json(products);
    } catch (error) {
        console.error(error);
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

createConnection().then(() => {
    app.listen(PORT, () => {
        console.log(`Server is running on port ${PORT}`);
    });
}).catch((error) => {
    console.error('Error connecting to the database:', error);
});